//   inQueueX: 2 * tile (x)
//   outQueueY: 2 * tile (y)
//   sigmoidQueue: 1 * tile (sigmoid output)
//   tmpUint8Queue: maxTmpSize bytes (estimated 8*tile floats = 2*tile floats)
